import{_ as t,o as d,c as n,ag as a}from"./chunks/framework.CvgP6Fyv.js";const p=JSON.parse('{"title":"API-Integration","description":"","frontmatter":{},"headers":[],"relativePath":"de/advanced/api.md","filePath":"de/advanced/api.md"}'),i={name:"de/advanced/api.md"};function r(s,e,o,l,c,h){return d(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="api-integration" tabindex="-1">API-Integration <a class="header-anchor" href="#api-integration" aria-label="Permalink to &quot;API-Integration&quot;">​</a></h1><p>Greifen Sie programmatisch auf Ihre MyCompanyDesk-Daten über die REST API zu.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>API-Zugang erfordert den <strong>Business</strong>-Tarif.</p></div><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><p>Die MyCompanyDesk API ermöglicht es Ihnen:</p><ul><li>Rechnungen, Ausgaben und Kunden zu erstellen und abzurufen</li><li>Abrechnungsworkflows zu automatisieren</li><li>Mit anderen Geschäftstools zu integrieren</li><li>Benutzerdefinierte Berichte zu erstellen</li><li>Daten mit externen Systemen zu synchronisieren</li></ul><h2 id="authentifizierung" tabindex="-1">Authentifizierung <a class="header-anchor" href="#authentifizierung" aria-label="Permalink to &quot;Authentifizierung&quot;">​</a></h2><p>Alle API-Anfragen erfordern einen API-Schlüssel, der im Anfrage-Header gesendet wird:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Authorization: Bearer YOUR_API_KEY</span></span></code></pre></div><h3 id="api-schlussel-erstellen" tabindex="-1">API-Schlüssel erstellen <a class="header-anchor" href="#api-schlussel-erstellen" aria-label="Permalink to &quot;API-Schlüssel erstellen&quot;">​</a></h3><ol><li>Gehen Sie zu <strong>Einstellungen &gt; API-Schlüssel</strong></li><li>Klicken Sie auf <strong>Neuen Schlüssel generieren</strong></li><li>Geben Sie dem Schlüssel einen aussagekräftigen Namen</li><li>Kopieren Sie den Schlüssel — er wird nur einmal angezeigt</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Bewahren Sie Ihren API-Schlüssel sicher auf. Speichern Sie ihn niemals in der Versionsverwaltung und teilen Sie ihn nicht öffentlich.</p></div><h2 id="basis-url" tabindex="-1">Basis-URL <a class="header-anchor" href="#basis-url" aria-label="Permalink to &quot;Basis-URL&quot;">​</a></h2><p>Alle API-Endpunkte sind verfügbar unter:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://api.mycompanydesk.com/api</span></span></code></pre></div><h2 id="wichtige-endpunkte" tabindex="-1">Wichtige Endpunkte <a class="header-anchor" href="#wichtige-endpunkte" aria-label="Permalink to &quot;Wichtige Endpunkte&quot;">​</a></h2><h3 id="kunden" tabindex="-1">Kunden <a class="header-anchor" href="#kunden" aria-label="Permalink to &quot;Kunden&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Methode</th><th>Endpunkt</th><th>Beschreibung</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/customers</code></td><td>Alle Kunden auflisten</td></tr><tr><td><code>POST</code></td><td><code>/customers</code></td><td>Kunden erstellen</td></tr><tr><td><code>GET</code></td><td><code>/customers/:id</code></td><td>Kunden abrufen</td></tr><tr><td><code>PUT</code></td><td><code>/customers/:id</code></td><td>Kunden aktualisieren</td></tr><tr><td><code>DELETE</code></td><td><code>/customers/:id</code></td><td>Kunden löschen</td></tr></tbody></table><h3 id="rechnungen" tabindex="-1">Rechnungen <a class="header-anchor" href="#rechnungen" aria-label="Permalink to &quot;Rechnungen&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Methode</th><th>Endpunkt</th><th>Beschreibung</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/invoices</code></td><td>Alle Rechnungen auflisten</td></tr><tr><td><code>POST</code></td><td><code>/invoices</code></td><td>Rechnung erstellen</td></tr><tr><td><code>GET</code></td><td><code>/invoices/:id</code></td><td>Rechnung abrufen</td></tr><tr><td><code>PUT</code></td><td><code>/invoices/:id</code></td><td>Rechnung aktualisieren</td></tr><tr><td><code>DELETE</code></td><td><code>/invoices/:id</code></td><td>Rechnung löschen</td></tr><tr><td><code>POST</code></td><td><code>/invoices/:id/send</code></td><td>Rechnung versenden</td></tr><tr><td><code>POST</code></td><td><code>/invoices/:id/mark-paid</code></td><td>Als bezahlt markieren</td></tr></tbody></table><h3 id="ausgaben" tabindex="-1">Ausgaben <a class="header-anchor" href="#ausgaben" aria-label="Permalink to &quot;Ausgaben&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Methode</th><th>Endpunkt</th><th>Beschreibung</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/expenses</code></td><td>Alle Ausgaben auflisten</td></tr><tr><td><code>POST</code></td><td><code>/expenses</code></td><td>Ausgabe erstellen</td></tr><tr><td><code>GET</code></td><td><code>/expenses/:id</code></td><td>Ausgabe abrufen</td></tr><tr><td><code>PUT</code></td><td><code>/expenses/:id</code></td><td>Ausgabe aktualisieren</td></tr><tr><td><code>DELETE</code></td><td><code>/expenses/:id</code></td><td>Ausgabe löschen</td></tr></tbody></table><h3 id="projekte" tabindex="-1">Projekte <a class="header-anchor" href="#projekte" aria-label="Permalink to &quot;Projekte&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Methode</th><th>Endpunkt</th><th>Beschreibung</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/projects</code></td><td>Alle Projekte auflisten</td></tr><tr><td><code>POST</code></td><td><code>/projects</code></td><td>Projekt erstellen</td></tr><tr><td><code>GET</code></td><td><code>/projects/:id</code></td><td>Projekt abrufen</td></tr><tr><td><code>PUT</code></td><td><code>/projects/:id</code></td><td>Projekt aktualisieren</td></tr></tbody></table><h3 id="suche" tabindex="-1">Suche <a class="header-anchor" href="#suche" aria-label="Permalink to &quot;Suche&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Methode</th><th>Endpunkt</th><th>Beschreibung</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/search?q=term&amp;type=entity</code></td><td>Über Entitäten suchen</td></tr></tbody></table><h2 id="filtern" tabindex="-1">Filtern <a class="header-anchor" href="#filtern" aria-label="Permalink to &quot;Filtern&quot;">​</a></h2><p>Listen-Endpunkte unterstützen Abfrageparameter zum Filtern:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /api/invoices?status=sent&amp;customer_id=123&amp;limit=50</span></span></code></pre></div><p>Häufige Filter:</p><ul><li><code>status</code> — Nach Status filtern</li><li><code>customer_id</code> — Nach Kunde filtern</li><li><code>project_id</code> — Nach Projekt filtern</li><li><code>limit</code> — Anzahl der Ergebnisse (Standard: 50)</li><li><code>offset</code> — Paginierungs-Offset</li></ul><h2 id="ratenbegrenzung" tabindex="-1">Ratenbegrenzung <a class="header-anchor" href="#ratenbegrenzung" aria-label="Permalink to &quot;Ratenbegrenzung&quot;">​</a></h2><p>API-Anfragen unterliegen einer Ratenbegrenzung, um faire Nutzung zu gewährleisten:</p><ul><li>Standard-Ratenbegrenzung gilt pro API-Schlüssel</li><li>Überschreitung des Limits gibt eine <code>429 Too Many Requests</code>-Antwort zurück</li><li>Integrieren Sie eine Wiederholungsstrategie in Ihre Integration</li></ul><h2 id="fehlerbehandlung" tabindex="-1">Fehlerbehandlung <a class="header-anchor" href="#fehlerbehandlung" aria-label="Permalink to &quot;Fehlerbehandlung&quot;">​</a></h2><p>Die API gibt Standard-HTTP-Statuscodes zurück:</p><table tabindex="0"><thead><tr><th>Code</th><th>Beschreibung</th></tr></thead><tbody><tr><td><code>200</code></td><td>Erfolg</td></tr><tr><td><code>201</code></td><td>Erstellt</td></tr><tr><td><code>400</code></td><td>Ungültige Anfrage (überprüfen Sie Ihre Parameter)</td></tr><tr><td><code>401</code></td><td>Nicht autorisiert (ungültiger API-Schlüssel)</td></tr><tr><td><code>403</code></td><td>Verboten (unzureichende Berechtigungen)</td></tr><tr><td><code>404</code></td><td>Nicht gefunden</td></tr><tr><td><code>429</code></td><td>Ratenbegrenzung erreicht</td></tr><tr><td><code>500</code></td><td>Serverfehler</td></tr></tbody></table><p>Fehlerantworten enthalten einen JSON-Body:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;error&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Beschreibung des aufgetretenen Fehlers&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h2><p>Konfigurieren Sie Webhooks, um Echtzeit-Benachrichtigungen zu erhalten, wenn Ereignisse auftreten:</p><ul><li>Rechnung versendet</li><li>Rechnung bezahlt</li><li>Kunde erstellt</li><li>Ausgabe hinzugefügt</li></ul><p>Richten Sie Webhooks unter <strong>Einstellungen &gt; API-Schlüssel &gt; Webhooks</strong> ein.</p><h2 id="tipps" tabindex="-1">Tipps <a class="header-anchor" href="#tipps" aria-label="Permalink to &quot;Tipps&quot;">​</a></h2><ul><li>Verwenden Sie Paginierung für große Datensätze</li><li>Cachen Sie Antworten, wo es sinnvoll ist, um API-Aufrufe zu reduzieren</li><li>Implementieren Sie Wiederholungslogik mit exponentiellem Backoff für Ratenbegrenzungen</li><li>Verwenden Sie Webhooks statt Polling für Echtzeit-Updates</li></ul>`,45)])])}const g=t(i,[["render",r]]);export{p as __pageData,g as default};
